```typescript
export type RouteState =
  | { status: "none" }
  | { status: "planned"; id: string; stops: number }
  | { status: "active"; id: string; stops: number; startedAt: string }
  | { status: "closed"; id: string };

export type RouteCommand =
  | { type: "plan"; id: string; stops: number }
  | { type: "activate"; at: string }
  | { type: "close"; at: string };

export type RouteEvent =
  | { type: "RoutePlanned"; id: string; stops: number }
  | { type: "RouteActivated"; at: string }
  | { type: "RouteClosed"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const routeDecider: Decider<RouteCommand, RouteEvent, RouteState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "plan":
        if (state.status !== "none") throw new DomainError("ROUTE_EXISTS");
        if (command.stops <= 0) throw new DomainError("NO_STOPS");
        return [{ type: "RoutePlanned", id: command.id, stops: command.stops }];
      case "activate":
        if (state.status === "active") throw new DomainError("ALREADY_ACTIVE");
        if (state.status !== "planned") throw new DomainError("NOT_PLANNED");
        return [{ type: "RouteActivated", at: command.at }];
      case "close":
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        return [{ type: "RouteClosed", at: command.at }];
      default: { const _n: never = command; throw new DomainError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "RoutePlanned":
        return { status: "planned", id: event.id, stops: event.stops };
      case "RouteActivated":
        if (state.status !== "planned") return state;
        return { status: "active", id: state.id, stops: state.stops, startedAt: event.at };
      case "RouteClosed":
        if (state.status !== "active") return state;
        return { status: "closed", id: state.id };
      default: { const _n: never = event; return state; }
    }
  },
};
