```typescript
export type LegState =
  | { status: "scheduled"; id: string; origin: string; destination: string }
  | { status: "inTransit"; id: string; origin: string; destination: string; startedAt: string }
  | { status: "completed"; id: string; at: string }
  | { status: "aborted"; id: string; reason: string };

export type LegCommand =
  | { type: "start"; at: string }
  | { type: "complete"; at: string }
  | { type: "abort"; reason: string };

export type LegEvent =
  | { type: "LegStarted"; at: string }
  | { type: "LegCompleted"; at: string }
  | { type: "LegAborted"; reason: string };

export class LegError extends Error {
  constructor(code: string) { super(code); this.name = "LegError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const makeLegDecider = (id: string, origin: string, destination: string): Decider<LegCommand, LegEvent, LegState> => ({
  initialState: { status: "scheduled", id, origin, destination },
  decide(c, s) {
    switch (c.type) {
      case "start":
        if (s.status !== "scheduled") throw new LegError("NOT_SCHEDULED");
        return [{ type: "LegStarted", at: c.at }];
      case "complete":
        if (s.status !== "inTransit") throw new LegError("NOT_IN_TRANSIT");
        return [{ type: "LegCompleted", at: c.at }];
      case "abort":
        if (s.status === "completed") throw new LegError("ALREADY_COMPLETED");
        if (s.status === "aborted") return [];
        return [{ type: "LegAborted", reason: c.reason }];
      default: { const _n: never = c; throw new LegError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "LegStarted":
        if (s.status !== "scheduled") return s;
        return { status: "inTransit", id: s.id, origin: s.origin, destination: s.destination, startedAt: e.at };
      case "LegCompleted":
        if (s.status !== "inTransit") return s;
        return { status: "completed", id: s.id, at: e.at };
      case "LegAborted":
        return { status: "aborted", id: "id" in s ? s.id : "", reason: e.reason };
      default: { const _n: never = e; return s; }
    }
  },
});
```

A Decider bundles three pure pieces: initialState, decide(command, state) returning events or throwing, and evolve(state, event) folding events into state. It has no I/O, which makes dispatch lifecycles trivially testable.

```typescript
export type DispatchState =
  | { status: "open"; id: string }
  | { status: "assigned"; id: string; driverId: string }
  | { status: "finalized"; id: string; driverId: string; at: string };

export type DispatchCommand =
  | { type: "assign"; driverId: string }
  | { type: "release" }
  | { type: "finalize"; at: string };

export type DispatchEvent =
  | { type: "DispatchAssigned"; driverId: string }
  | { type: "DispatchReleased" }
  | { type: "DispatchFinalized"; at: string };

export class DispatchError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const makeDispatchDecider = (id: string): Decider<DispatchCommand, DispatchEvent, DispatchState> => ({
  initialState: { status: "open", id },
  decide(c, s) {
    switch (c.type) {
      case "assign":
        if (s.status !== "open") throw new DispatchError("NOT_OPEN");
        return [{ type: "DispatchAssigned", driverId: c.driverId }];
      case "release":
        if (s.status !== "assigned") throw new DispatchError("NOT_ASSIGNED");
        return [{ type: "DispatchReleased" }];
      case "finalize":
        if (s.status !== "assigned") throw new DispatchError("NOT_ASSIGNED");
        return [{ type: "DispatchFinalized", at: c.at }];
      default: { const _n: never = c; throw new DispatchError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "DispatchAssigned":
        if (s.status !== "open") return s;
        return { status: "assigned", id: s.id, driverId: e.driverId };
      case "DispatchReleased":
        if (s.status !== "assigned") return s;
        return { status: "open", id: s.id };
      case "DispatchFinalized":
        if (s.status !== "assigned") return s;
        return { status: "finalized", id: s.id, driverId: s.driverId, at: e.at };
      default: { const _n: never = e; return s; }
    }
  },
});
