```typescript
export type RideShareState =
  | { status: "requested"; id: string; riderId: string }
  | { status: "matched"; id: string; riderId: string; driverId: string }
  | { status: "completed"; id: string; at: string }
  | { status: "cancelled"; id: string; reason: string };

export type RideShareCommand =
  | { type: "request"; id: string; riderId: string }
  | { type: "match"; driverId: string }
  | { type: "complete"; at: string }
  | { type: "cancel"; reason: string };

export type RideShareEvent =
  | { type: "RideShareRequested"; id: string; riderId: string }
  | { type: "RideShareMatched"; driverId: string }
  | { type: "RideShareCompleted"; at: string }
  | { type: "RideShareCancelled"; reason: string };

export class RideShareError extends Error {
  constructor(code: string) { super(code); this.name = "RideShareError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export function decide(command: RideShareCommand, state: RideShareState | null): RideShareEvent[] {
  switch (command.type) {
    case "request":
      if (state) throw new RideShareError("ALREADY_REQUESTED");
      return [{ type: "RideShareRequested", id: command.id, riderId: command.riderId }];
    case "match":
      if (!state || state.status !== "requested") throw new RideShareError("NOT_REQUESTED");
      return [{ type: "RideShareMatched", driverId: command.driverId }];
    case "complete":
      if (!state || state.status !== "matched") throw new RideShareError("NOT_MATCHED");
      return [{ type: "RideShareCompleted", at: command.at }];
    case "cancel":
      if (!state) throw new RideShareError("NOT_FOUND");
      if (state.status === "completed") throw new RideShareError("ALREADY_COMPLETED");
      if (state.status === "cancelled") return [];
      return [{ type: "RideShareCancelled", reason: command.reason }];
    default: { const _n: never = command; throw new RideShareError("UNKNOWN"); }
  }
}

export function evolve(state: RideShareState | null, event: RideShareEvent): RideShareState {
  switch (event.type) {
    case "RideShareRequested":
      return { status: "requested", id: event.id, riderId: event.riderId };
    case "RideShareMatched":
      if (!state || state.status !== "requested") return state ?? { status: "cancelled", id: "", reason: "invalid" };
      return { status: "matched", id: state.id, riderId: state.riderId, driverId: event.driverId };
    case "RideShareCompleted":
      if (!state) return { status: "completed", id: "", at: event.at };
      return { status: "completed", id: "id" in state ? state.id : "", at: event.at };
    case "RideShareCancelled":
      return { status: "cancelled", id: state && "id" in state ? state.id : "", reason: event.reason };
    default: { const _n: never = event; return state ?? { status: "cancelled", id: "", reason: "unknown" }; }
  }
}
