```typescript
export type CourierState =
  | { status: "pending" }
  | { status: "offline"; id: string; name: string }
  | { status: "online"; id: string; name: string; since: string }
  | { status: "offboarded"; id: string };

export type CourierCommand =
  | { type: "onboard"; id: string; name: string }
  | { type: "goOnline"; at: string }
  | { type: "goOffline" }
  | { type: "offboard" };

export type CourierEvent =
  | { type: "CourierOnboarded"; id: string; name: string }
  | { type: "CourierWentOnline"; at: string }
  | { type: "CourierWentOffline" }
  | { type: "CourierOffboarded" };

export class CourierError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const courierDecider: Decider<CourierCommand, CourierEvent, CourierState> = {
  initialState: { status: "pending" },
  decide(c, s) {
    switch (c.type) {
      case "onboard":
        if (s.status !== "pending") throw new CourierError("ALREADY_ONBOARDED");
        return [{ type: "CourierOnboarded", id: c.id, name: c.name }];
      case "goOnline":
        if (s.status !== "offline") throw new CourierError("NOT_OFFLINE");
        return [{ type: "CourierWentOnline", at: c.at }];
      case "goOffline":
        if (s.status !== "online") throw new CourierError("NOT_ONLINE");
        return [{ type: "CourierWentOffline" }];
      case "offboard":
        if (s.status === "offboarded" || s.status === "pending") throw new CourierError("CANNOT_OFFBOARD");
        return [{ type: "CourierOffboarded" }];
      default: { const _n: never = c; throw new CourierError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "CourierOnboarded":
        return { status: "offline", id: e.id, name: e.name };
      case "CourierWentOnline":
        if (s.status !== "offline") return s;
        return { status: "online", id: s.id, name: s.name, since: e.at };
      case "CourierWentOffline":
        if (s.status !== "online") return s;
        return { status: "offline", id: s.id, name: s.name };
      case "CourierOffboarded":
        if (s.status === "pending") return s;
        return { status: "offboarded", id: "id" in s ? s.id : "" };
      default: { const _n: never = e; return s; }
    }
  },
};
