```typescript
export type RouteFeedEvent =
  | { type: "RoutePlanned"; routeId: string; label: string }
  | { type: "LegScheduled"; routeId: string }
  | { type: "LegCompleted"; routeId: string }
  | { type: "RouteActivated"; routeId: string }
  | { type: "RouteClosed"; routeId: string };

type RouteStatus = "planned" | "active" | "closed";

export interface RouteRow {
  readonly label: string;
  readonly totalLegs: number;
  readonly completedLegs: number;
  readonly status: RouteStatus;
}

export interface RouteSummary {
  readonly rows: Readonly<Record<string, RouteRow>>;
}

export const emptyView: RouteSummary = { rows: {} };

function upsert(view: RouteSummary, routeId: string, patch: Partial<RouteRow>, seed?: RouteRow): RouteSummary {
  const prev = view.rows[routeId] ?? seed;
  if (!prev) return view;
  return { rows: { ...view.rows, [routeId]: { ...prev, ...patch } } };
}

export function project(view: RouteSummary, event: RouteFeedEvent): RouteSummary {
  switch (event.type) {
    case "RoutePlanned":
      return upsert(view, event.routeId, {}, { label: event.label, totalLegs: 0, completedLegs: 0, status: "planned" });
    case "LegScheduled": {
      const prev = view.rows[event.routeId];
      if (!prev) return view;
      return upsert(view, event.routeId, { totalLegs: prev.totalLegs + 1 });
    }
    case "LegCompleted": {
      const prev = view.rows[event.routeId];
      if (!prev) return view;
      return upsert(view, event.routeId, { completedLegs: prev.completedLegs + 1 });
    }
    case "RouteActivated":
      return upsert(view, event.routeId, { status: "active" });
    case "RouteClosed":
      return upsert(view, event.routeId, { status: "closed" });
    default: { const _n: never = event; return view; }
  }
}
