```typescript
export type DropOffEvent =
  | { type: "DropOffSucceeded"; courierId: string; at: string }
  | { type: "DropOffFailed"; courierId: string; reason: string }
  | { type: "DropOffRescheduled"; courierId: string };

export interface CourierScore {
  readonly successes: number;
  readonly failures: number;
}

export interface DropOffView {
  readonly byCourier: Readonly<Record<string, CourierScore>>;
}

export const emptyView: DropOffView = { byCourier: {} };

function bump(view: DropOffView, courierId: string, patch: Partial<CourierScore>): DropOffView {
  const prev: CourierScore = view.byCourier[courierId] ?? { successes: 0, failures: 0 };
  return {
    byCourier: {
      ...view.byCourier,
      [courierId]: {
        successes: prev.successes + (patch.successes ?? 0),
        failures: prev.failures + (patch.failures ?? 0),
      },
    },
  };
}

export function project(view: DropOffView, event: DropOffEvent): DropOffView {
  switch (event.type) {
    case "DropOffSucceeded":
      return bump(view, event.courierId, { successes: 1 });
    case "DropOffFailed":
      return bump(view, event.courierId, { failures: 1 });
    case "DropOffRescheduled":
      return view;
    default: { const _n: never = event; return view; }
  }
}

export function replay(events: readonly DropOffEvent[]): DropOffView {
  return events.reduce(project, emptyView);
}
