```typescript
export interface RouteProfile {
  readonly id: string;
  readonly label: string;
  readonly stops: number;
  readonly status: "planned" | "active" | "closed";
  readonly totalDistanceKm: number;
}

export type Snapshot<S> = { version: number; state: S };
export const CURRENT_VERSION = 3;

interface RouteV1 { id: string; label: string; stops: number }
interface RouteV2 { id: string; label: string; stops: number; status: "planned" | "active" | "closed" }

function v1Tov2(snap: Snapshot<RouteV1>): Snapshot<RouteV2> {
  return { version: 2, state: { ...snap.state, status: "planned" } };
}

function v2Tov3(snap: Snapshot<RouteV2>): Snapshot<RouteProfile> {
  return { version: 3, state: { ...snap.state, totalDistanceKm: 0 } };
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<RouteProfile> {
  let current: Snapshot<unknown> = raw;
  if (current.version === 1) current = v1Tov2(current as Snapshot<RouteV1>);
  if (current.version === 2) current = v2Tov3(current as Snapshot<RouteV2>);
  if (current.version !== CURRENT_VERSION) throw new Error("unsupported-version");
  return current as Snapshot<RouteProfile>;
}

export function loadRoute(raw: Snapshot<unknown>): RouteProfile {
  return upgradeSnapshot(raw).state;
}
```

Snapshots persist aggregate state with a version tag. On load the loader runs upgraders from the stored version up to CURRENT_VERSION, so rolling schema changes never require rewriting the event stream.

```typescript
export interface CourierProfile {
  readonly id: string;
  readonly name: string;
  readonly status: "online" | "offline" | "offboarded";
  readonly vehicleId: string | null;
}

export type Snapshot<S> = { version: number; state: S };
export const CURRENT_VERSION = 3;

interface CourierV1 { id: string; name: string; online: boolean }
interface CourierV2 { id: string; name: string; status: "online" | "offline" | "offboarded" }

function v1Tov2(snap: Snapshot<CourierV1>): Snapshot<CourierV2> {
  return { version: 2, state: { id: snap.state.id, name: snap.state.name, status: snap.state.online ? "online" : "offline" } };
}

function v2Tov3(snap: Snapshot<CourierV2>): Snapshot<CourierProfile> {
  return { version: 3, state: { ...snap.state, vehicleId: null } };
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<CourierProfile> {
  let s: Snapshot<unknown> = raw;
  if (s.version === 1) s = v1Tov2(s as Snapshot<CourierV1>);
  if (s.version === 2) s = v2Tov3(s as Snapshot<CourierV2>);
  if (s.version !== CURRENT_VERSION) throw new Error("bad-version");
  return s as Snapshot<CourierProfile>;
}
