  readStream(stream: string): AsyncIterable<StoredEvent<E>>;
  appendToStream(stream: string, events: readonly E[], options: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: ExpectedRevision) {
    super(`Concurrency conflict on ${stream}`);
    this.name = "ConcurrencyConflict";
