  const e = raw as RawEvent;
  switch (e.type) {
    case "RoutePlanned": {
      if (e.version === 1) {
        return { type: "RoutePlanned", version: 2, id: String(e.id), stops: parseStops(e.stops) };
      }
      if (e.version === 2) {
        return { type: "RoutePlanned", version: 2, id: String(e.id), stops: Number(e.stops) };
      }
      throw new UnknownEventError(raw);
    }
    case "RouteActivated":
      return { type: "RouteActivated", version: 1, at: String(e.at ?? "") };
    case "RouteClosed":
      return { type: "RouteClosed", version: 1, at: String(e.at ?? "") };
    default:
      throw new UnknownEventError(raw);
  }
}

export interface EventStore {
  readStream(stream: string): AsyncIterable<unknown>;
}

export async function readAllUpcast(store: EventStore, streamName: string): Promise<readonly RouteEvent[]> {
  const out: RouteEvent[] = [];
  for await (const raw of store.readStream(streamName)) {
    out.push(upcast(raw));
  }
  return out;
}
