export type DropOffEvent =
  | { type: "DropOffSucceeded"; id: string; at: string }
  | { type: "DropOffFailed"; id: string; reason: string };

export interface PositionedEvent { position: bigint; event: DropOffEvent }

export interface EventReader {
  read(from: bigint, batchSize: number): Promise<readonly PositionedEvent[]>;
}

export interface DropOffRow { status: "succeeded" | "failed"; info: string }

export interface ReadStore {
  persistBatch(rows: Readonly<Record<string, DropOffRow>>): Promise<void>;
  setCursor(pos: bigint): Promise<void>;
}

export interface ProgressSink { report(count: number, cursor: bigint): void }

function project(rows: Readonly<Record<string, DropOffRow>>, e: DropOffEvent): Readonly<Record<string, DropOffRow>> {
  switch (e.type) {
    case "DropOffSucceeded": return { ...rows, [e.id]: { status: "succeeded", info: e.at } };
    case "DropOffFailed": return { ...rows, [e.id]: { status: "failed", info: e.reason } };
    default: { const _n: never = e; return rows; }
  }
}

export async function rebuild(opts: { from: bigint; batchSize: number; reader: EventReader; store: ReadStore; progress: ProgressSink }): Promise<void> {
  let cursor = opts.from;
  let total = 0;
  while (true) {
    const batch = await opts.reader.read(cursor, opts.batchSize);
    if (batch.length === 0) return;
    let rows: Readonly<Record<string, DropOffRow>> = {};
    for (const { event } of batch) {
      rows = project(rows, event);
    }
    await opts.store.persistBatch(rows);
    total += batch.length;
    cursor = batch[batch.length - 1].position + 1n;
    await opts.store.setCursor(cursor);
    opts.progress.report(total, cursor);
  }
}
