type ExpectedRevision = bigint | "no_stream" | "any";

export interface StoredEvent<E> { revision: bigint; event: E }

export interface EventStore<E> {
  readStream(s: string): AsyncIterable<StoredEvent<E>>;
  appendToStream(s: string, events: readonly E[], o: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export type RouteState =
  | { status: "none" }
  | { status: "planned"; id: string; stops: number }
  | { status: "active"; id: string; stops: number };

export type RouteCommand = { type: "plan"; id: string; stops: number } | { type: "activate"; at: string };
export type RouteEvent = { type: "RoutePlanned"; id: string; stops: number } | { type: "RouteActivated"; at: string };

function evolve(s: RouteState, e: RouteEvent): RouteState {
  switch (e.type) {
    case "RoutePlanned": return { status: "planned", id: e.id, stops: e.stops };
    case "RouteActivated":
      if (s.status !== "planned") return s;
      return { status: "active", id: s.id, stops: s.stops };
    default: { const _n: never = e; return s; }
  }
}

function decide(c: RouteCommand, s: RouteState): RouteEvent[] {
  switch (c.type) {
    case "plan":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "RoutePlanned", id: c.id, stops: c.stops }];
    case "activate":
      if (s.status !== "planned") throw new Error("NOT_PLANNED");
      return [{ type: "RouteActivated", at: c.at }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export interface RouteRow { id: string; label: string; stops: number; status: "planned" | "active" }

export interface ReadStore {
  find(id: string): Promise<RouteRow | null>;
}

export async function handleCommand(store: EventStore<RouteEvent>, streamName: string, command: RouteCommand): Promise<void> {
  let state: RouteState = { status: "none" };
  let revision: bigint | undefined;
  for await (const { event, revision: r } of store.readStream(streamName)) {
    state = evolve(state, event);
    revision = r;
  }
  const events = decide(command, state);
  if (events.length === 0) return;
  // Read store is eventually consistent with the event store; a projection worker catches it up.
  await store.appendToStream(streamName, events, { expectedRevision: revision ?? "no_stream" });
}

export async function queryView(read: ReadStore, id: string): Promise<RouteRow | null> {
  return read.find(id);
}
