Outbox rows and the event store append must succeed or fail together. Declare a local transactional conn so the code doesn't pull in any real driver. A worker process later polls outbox rows and marks them published.

```typescript
type ExpectedRevision = bigint | "no_stream" | "any";

export interface OutboxRow {
  readonly id: string;
  readonly payload: string;
  readonly publishedAt: string | null;
}

export interface TransactionalConn {
  insertOutbox(rows: readonly OutboxRow[]): Promise<void>;
}

export interface EventStore<E> {
  appendToStream(stream: string, events: readonly E[], options: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export interface UnitOfWork {
  run<T>(fn: (conn: TransactionalConn, store: EventStore<DispatchEvent>) => Promise<T>): Promise<T>;
}

export type DispatchEvent =
  | { type: "DispatchAssigned"; dispatchId: string; driverId: string }
  | { type: "DispatchReleased"; dispatchId: string };

export async function appendWithOutbox(
  uow: UnitOfWork,
  streamName: string,
  events: readonly DispatchEvent[],
  outboxRows: readonly OutboxRow[],
  expected: ExpectedRevision,
): Promise<bigint> {
  // The publisher is a separate worker: poll unpublished rows, publish, then mark publishedAt.
  return uow.run(async (conn, store) => {
    await conn.insertOutbox(outboxRows);
    const { nextRevision } = await store.appendToStream(streamName, events, { expectedRevision: expected });
    return nextRevision;
  });
}
```

Event sourcing expresses the same lifecycle through a pure Decider: decide turns commands into events, evolve folds events into state, and the initial state is a literal.

```typescript
export type RouteState =
  | { status: "none" }
  | { status: "planned"; id: string }
  | { status: "active"; id: string; activatedAt: string };

export type RouteCommand =
  | { type: "plan"; id: string }
  | { type: "activate"; at: string };

export type RouteEvent =
  | { type: "RoutePlanned"; id: string }
  | { type: "RouteActivated"; at: string };

export class RouteError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const routeDecider: Decider<RouteCommand, RouteEvent, RouteState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "plan":
        if (s.status !== "none") throw new RouteError("EXISTS");
        return [{ type: "RoutePlanned", id: c.id }];
      case "activate":
        if (s.status !== "planned") throw new RouteError("NOT_PLANNED");
        return [{ type: "RouteActivated", at: c.at }];
      default: { const _n: never = c; throw new RouteError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "RoutePlanned":
        return { status: "planned", id: e.id };
      case "RouteActivated":
        if (s.status !== "planned") return s;
        return { status: "active", id: s.id, activatedAt: e.at };
      default: { const _n: never = e; return s; }
    }
  },
};
