export type LegState =
  | { status: "scheduled"; id: string }
  | { status: "completed"; id: string; at: string }
  | { status: "aborted"; id: string; reason: string };

export type LegCommand =
  | { type: "complete"; at: string }
  | { type: "abort"; reason: string };

export type LegEvent =
  | { type: "LegCompleted"; at: string }
  | { type: "LegAborted"; reason: string };

export class LegError extends Error {
  constructor(code: string) { super(code); this.name = "LegError"; }
}

export function decide(command: LegCommand, state: LegState): LegEvent[] {
  switch (command.type) {
    case "complete":
      if (state.status !== "scheduled") throw new LegError("NOT_SCHEDULED");
      return [{ type: "LegCompleted", at: command.at }];
    case "abort":
      if (state.status === "completed") throw new LegError("ALREADY_COMPLETED");
      if (state.status === "aborted") return [];
      return [{ type: "LegAborted", reason: command.reason }];
    default: { const _n: never = command; throw new LegError("UNKNOWN"); }
  }
}

export function evolve(state: LegState, event: LegEvent): LegState {
  switch (event.type) {
    case "LegCompleted":
      if (state.status !== "scheduled") return state;
      return { status: "completed", id: state.id, at: event.at };
    case "LegAborted":
      if (state.status === "completed") return state;
      return { status: "aborted", id: state.id, reason: event.reason };
    default: { const _n: never = event; return state; }
  }
}
```

